import{c as e,Q as a,j as d,m as r}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"03 · Orrery — Data Catalog","description":"","frontmatter":{},"headers":[],"relativePath":"concept/03_Data_Catalog.md","filePath":"concept/03_Data_Catalog.md"}'),o={name:"concept/03_Data_Catalog.md"};function i(s,t,n,l,c,h){return a(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="_03-·-orrery-—-data-catalog" tabindex="-1">03 · Orrery — Data Catalog <a class="header-anchor" href="#_03-·-orrery-—-data-catalog" aria-label="Permalink to &quot;03 · Orrery — Data Catalog&quot;">​</a></h1><p><em>April 2026 · v1.0 · Part of the Orrery Concept Package (00 through 05)</em></p><hr><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>This document catalogs every data source, constant, schema, and API that Orrery uses. It is the primary reference for anyone adding a mission, correcting a number, or building on the codebase. Every value in the product traces back to something in this document.</p><hr><h2 id="_1-orbital-mechanics" tabindex="-1">1. Orbital mechanics <a class="header-anchor" href="#_1-orbital-mechanics" aria-label="Permalink to &quot;1. Orbital mechanics&quot;">​</a></h2><h3 id="_1-1-physical-constants" tabindex="-1">1.1 Physical constants <a class="header-anchor" href="#_1-1-physical-constants" aria-label="Permalink to &quot;1.1 Physical constants&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Constant</th><th>Value</th><th>Source</th></tr></thead><tbody><tr><td>Gravitational parameter (Sun) μ</td><td>4π² AU³/yr²</td><td>Keplerian simplification; GM☉ = 1.327×10²⁰ m³/s²</td></tr><tr><td>AU to km</td><td>149,597,870.7 km</td><td>IAU 2012</td></tr><tr><td>AU to light-minutes</td><td>8.3167 min</td><td>Derived from c = 299,792.458 km/s</td></tr><tr><td>AU/yr to km/s</td><td>4.7404 km/s</td><td>Derived</td></tr><tr><td>Earth radius</td><td>6,371 km</td><td>IAU</td></tr><tr><td>Moon radius</td><td>1,737.4 km</td><td>IAU</td></tr><tr><td>Earth–Moon mean distance</td><td>384,400 km</td><td>IAU</td></tr><tr><td>Earth–Sun mean distance</td><td>1.000 AU (definition)</td><td>IAU</td></tr></tbody></table><h3 id="_1-2-epoch" tabindex="-1">1.2 Epoch <a class="header-anchor" href="#_1-2-epoch" aria-label="Permalink to &quot;1.2 Epoch&quot;">​</a></h3><p>All orbital elements use the <strong>J2000.0 epoch</strong> (January 1.5, 2000, 12:00 TT = JD 2451545.0). Day offsets from J2000 are used throughout the mission trajectory computation.</p><h3 id="_1-3-planetary-orbital-elements" tabindex="-1">1.3 Planetary orbital elements <a class="header-anchor" href="#_1-3-planetary-orbital-elements" aria-label="Permalink to &quot;1.3 Planetary orbital elements&quot;">​</a></h3><p>Mean orbital radii and angular velocity used in Orrery&#39;s Keplerian model. These are mean values — Orrery does not model orbital eccentricity for planets in the explorer view, trading precision for visual clarity and performance. The mission configurator uses a Lambert solver for trajectory accuracy.</p><table tabindex="0"><thead><tr><th>Planet</th><th>Semi-major axis</th><th>Period</th><th>Mean angular velocity</th><th>J2000 mean longitude L₀</th><th>Inclination to ecliptic</th></tr></thead><tbody><tr><td>Mercury</td><td>0.387 AU</td><td>87.97 d</td><td>2π / 87.97 d</td><td>Varies</td><td>7.00°</td></tr><tr><td>Venus</td><td>0.723 AU</td><td>224.70 d</td><td>2π / 224.70 d</td><td>Varies</td><td>3.39°</td></tr><tr><td>Earth</td><td>1.000 AU</td><td>365.25 d</td><td>2π / 365.25 d</td><td>1.753 rad</td><td>0.00° (reference)</td></tr><tr><td>Mars</td><td>1.524 AU</td><td>686.97 d</td><td>2π / 686.97 d</td><td>6.203 rad</td><td>1.85°</td></tr><tr><td>Jupiter</td><td>5.203 AU</td><td>4332.59 d</td><td>2π / 4332.59 d</td><td>—</td><td>1.30°</td></tr><tr><td>Saturn</td><td>9.537 AU</td><td>10759.22 d</td><td>2π / 10759.22 d</td><td>—</td><td>2.49°</td></tr><tr><td>Uranus</td><td>19.19 AU</td><td>30688.50 d</td><td>2π / 30688.50 d</td><td>—</td><td>0.77°</td></tr><tr><td>Neptune</td><td>30.07 AU</td><td>60182.00 d</td><td>2π / 60182.00 d</td><td>—</td><td>1.77°</td></tr></tbody></table><p><strong>Source:</strong> JPL Planetary Fact Sheets — <a href="https://nssdc.gsfc.nasa.gov/planetary/factsheet/" target="_blank" rel="noreferrer">https://nssdc.gsfc.nasa.gov/planetary/factsheet/</a></p><h3 id="_1-4-mission-orbital-position-computation" tabindex="-1">1.4 Mission orbital position computation <a class="header-anchor" href="#_1-4-mission-orbital-position-computation" aria-label="Permalink to &quot;1.4 Mission orbital position computation&quot;">​</a></h3><p>For the porkchop plot and mission arc, planetary positions are computed using:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>angle(t) = L₀ + ω × t</span></span>
<span class="line"><span>x = r × cos(angle)</span></span>
<span class="line"><span>y = r × sin(angle) × cos(inclination)</span></span>
<span class="line"><span>z = r × sin(angle) × sin(inclination)</span></span></code></pre></div><p>Where <code>t</code> is days from J2000, <code>ω</code> is angular velocity in rad/day, and <code>r</code> is the mean orbital radius in AU.</p><h3 id="_1-5-lambert-solver" tabindex="-1">1.5 Lambert solver <a class="header-anchor" href="#_1-5-lambert-solver" aria-label="Permalink to &quot;1.5 Lambert solver&quot;">​</a></h3><p>The porkchop plot is computed using a bisection-based Lambert solver:</p><ul><li><strong>Method:</strong> Lagrange-Gauss short-way formulation</li><li><strong>Iterations:</strong> 52 per cell (convergence to ≤10⁻⁸ tolerance)</li><li><strong>Grid:</strong> 140 × 80 = 11,200 trajectory solutions computed at startup</li><li><strong>X axis:</strong> Departure date (days from reference)</li><li><strong>Y axis:</strong> Time of flight (days)</li><li><strong>Z / colour:</strong> C3 launch energy (km²/s²), rendered as delta-v approximation</li><li><strong>Reference:</strong> Bate, Mueller &amp; White, <em>Fundamentals of Astrodynamics</em> (1971), Chapter 5</li></ul><h3 id="_1-6-transfer-orbit-—-hohmann-approximation" tabindex="-1">1.6 Transfer orbit — Hohmann approximation <a class="header-anchor" href="#_1-6-transfer-orbit-—-hohmann-approximation" aria-label="Permalink to &quot;1.6 Transfer orbit — Hohmann approximation&quot;">​</a></h3><p>For the mission arc fly screen, spacecraft position is interpolated along a quadratic Bézier curve between Earth&#39;s departure position and Mars&#39;s arrival position. This is a visual approximation of the true Keplerian transfer ellipse, used for rendering only. Telemetry (velocity, distance) is computed from the vis-viva equation applied to the actual transfer orbit elements.</p><p><strong>Vis-viva:</strong> <code>v = √(μ × (2/r − 1/a))</code></p><p>Where:</p><ul><li><code>μ</code> = 4π² AU³/yr² (solar gravitational parameter)</li><li><code>r</code> = current heliocentric distance (AU)</li><li><code>a</code> = semi-major axis of transfer orbit = (R_Earth + R_Mars) / 2 = 1.262 AU</li></ul><h3 id="_1-7-visual-scale-—-solar-system-explorer" tabindex="-1">1.7 Visual scale — solar system explorer <a class="header-anchor" href="#_1-7-visual-scale-—-solar-system-explorer" aria-label="Permalink to &quot;1.7 Visual scale — solar system explorer&quot;">​</a></h3><p>Planets are not shown at true scale — they would be invisible. The visual orbital radii used in the 2D and 3D explorer are:</p><table tabindex="0"><thead><tr><th>Body</th><th>True semi-major axis</th><th>Visual orbital radius (px)</th><th>Scale factor</th></tr></thead><tbody><tr><td>Mercury</td><td>0.387 AU</td><td>52 px</td><td>—</td></tr><tr><td>Venus</td><td>0.723 AU</td><td>83 px</td><td>—</td></tr><tr><td>Earth</td><td>1.000 AU</td><td>113 px</td><td>Reference</td></tr><tr><td>Mars</td><td>1.524 AU</td><td>155 px</td><td>—</td></tr><tr><td>Asteroid belt</td><td>2.2–3.2 AU</td><td>192–237 px</td><td>—</td></tr><tr><td>Jupiter</td><td>5.203 AU</td><td>248 px</td><td>—</td></tr><tr><td>Saturn</td><td>9.537 AU</td><td>320 px</td><td>—</td></tr><tr><td>Uranus</td><td>19.19 AU</td><td>378 px</td><td>—</td></tr><tr><td>Neptune</td><td>30.07 AU</td><td>430 px</td><td>—</td></tr><tr><td>Kuiper Belt</td><td>30–50 AU</td><td>438–470 px</td><td>—</td></tr></tbody></table><p>The scale is manually compressed (not a pure power law) to keep all planets visible on a single screen while preserving relative ordering. The <code>auToPx()</code> function in P01 implements a linear interpolation between these anchor points.</p><h3 id="_1-8-visual-scale-—-earth-orbit-viewer" tabindex="-1">1.8 Visual scale — Earth orbit viewer <a class="header-anchor" href="#_1-8-visual-scale-—-earth-orbit-viewer" aria-label="Permalink to &quot;1.8 Visual scale — Earth orbit viewer&quot;">​</a></h3><p>The Earth orbit viewer uses a logarithmic scale to accommodate the ISS-to-JWST range of 3,750×:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>visual_r = EARTH_VIS_R + LOG_K × log₁₀(1 + alt_km / 100)</span></span></code></pre></div><p>Where <code>EARTH_VIS_R = 38 px</code> (visual Earth radius) and <code>LOG_K = 54 px</code> (scale factor per decade of altitude). This maps ISS (408 km) to ~70 px and JWST (1,500,000 km) to ~244 px.</p><hr><h2 id="_2-mission-data-schema" tabindex="-1">2. Mission data schema <a class="header-anchor" href="#_2-mission-data-schema" aria-label="Permalink to &quot;2. Mission data schema&quot;">​</a></h2><p>Every mission in Orrery is defined by a JavaScript object conforming to this schema. This schema covers both Mars and Moon missions.</p><h3 id="_2-1-required-fields" tabindex="-1">2.1 Required fields <a class="header-anchor" href="#_2-1-required-fields" aria-label="Permalink to &quot;2.1 Required fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>string</td><td>Unique identifier, kebab-case. e.g. <code>&quot;curiosity&quot;</code>, <code>&quot;apollo11m&quot;</code></td></tr><tr><td><code>name</code></td><td>string</td><td>Display name. e.g. <code>&quot;Curiosity&quot;</code>, <code>&quot;Apollo 11&quot;</code></td></tr><tr><td><code>agency</code></td><td>string</td><td>Primary agency key. Must match <code>LOGOS</code> dict. e.g. <code>&quot;NASA&quot;</code>, <code>&quot;CNSA&quot;</code></td></tr><tr><td><code>agency_full</code></td><td>string</td><td>Full display name. e.g. <code>&quot;NASA / JPL&quot;</code></td></tr><tr><td><code>sector</code></td><td>string</td><td><code>&quot;gov&quot;</code>, <code>&quot;private&quot;</code>, or <code>&quot;mine&quot;</code></td></tr><tr><td><code>dest</code></td><td>string</td><td><code>&quot;MARS&quot;</code> or <code>&quot;MOON&quot;</code></td></tr><tr><td><code>color</code></td><td>string</td><td>Hex colour for agency. e.g. <code>&quot;#0B3D91&quot;</code></td></tr><tr><td><code>year</code></td><td>number or string</td><td>Launch year. Use string for ranges: <code>&quot;2026–28&quot;</code></td></tr><tr><td><code>type</code></td><td>string</td><td>Mission type description. e.g. <code>&quot;ROVER · ACTIVE&quot;</code></td></tr><tr><td><code>status</code></td><td>string</td><td><code>&quot;FLOWN&quot;</code>, <code>&quot;ACTIVE&quot;</code>, <code>&quot;PLANNED&quot;</code>, or <code>&quot;MINE&quot;</code></td></tr><tr><td><code>dep</code></td><td>string</td><td>Departure date, human-readable. e.g. <code>&quot;Nov 26, 2011&quot;</code></td></tr><tr><td><code>arr</code></td><td>string</td><td>Arrival date, human-readable. e.g. <code>&quot;Aug 6, 2012&quot;</code></td></tr><tr><td><code>tof</code></td><td>number or null</td><td>Transit time in days. <code>null</code> for TBD planned missions</td></tr><tr><td><code>vehicle</code></td><td>string</td><td>Launch vehicle name</td></tr><tr><td><code>description</code></td><td>string</td><td>Editorial description, 2–4 sentences, Crimson Pro italic in UI</td></tr><tr><td><code>data_quality</code></td><td>string</td><td><code>&quot;good&quot;</code>, <code>&quot;partial&quot;</code>, <code>&quot;reconstructed&quot;</code>, or <code>&quot;planned&quot;</code></td></tr><tr><td><code>credit</code></td><td>string</td><td>Full image/data credit line</td></tr><tr><td><code>links</code></td><td>array</td><td>Array of <code>{l, u, t}</code> educational link objects (see 2.3)</td></tr><tr><td><code>missionable</code></td><td>boolean</td><td><code>true</code> only for Mars — shows &quot;Plan a mission&quot; CTA</td></tr></tbody></table><h3 id="_2-2-optional-fields" tabindex="-1">2.2 Optional fields <a class="header-anchor" href="#_2-2-optional-fields" aria-label="Permalink to &quot;2.2 Optional fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>j2000</code></td><td>number or null</td><td>Days from J2000 epoch at departure. Used for trajectory preview drawing. <code>null</code> for Moon missions and TBD planned missions</td></tr><tr><td><code>collabs</code></td><td>array</td><td>Array of collaborating agency keys. e.g. <code>[&quot;ESA&quot;, &quot;CNES&quot;]</code></td></tr><tr><td><code>first</code></td><td>string</td><td>The mission&#39;s &quot;first&quot; — shown as a coloured badge in the card</td></tr><tr><td><code>payload</code></td><td>string</td><td>Payload mass description. e.g. <code>&quot;899 kg&quot;</code></td></tr><tr><td><code>dv</code></td><td>string</td><td>Delta-v figure. e.g. <code>&quot;~6.1 km/s&quot;</code></td></tr><tr><td><code>data_note</code></td><td>string</td><td>Explanation for non-&quot;good&quot; data quality. Shown as a left-border note in the panel</td></tr><tr><td><code>gallery_query</code></td><td>string</td><td>Search query string for NASA Images API. NASA missions only</td></tr><tr><td><code>gallery_imgs</code></td><td>array</td><td>Array of direct image URLs. For non-NASA missions. See section 4</td></tr></tbody></table><h3 id="_2-3-educational-link-object" tabindex="-1">2.3 Educational link object <a class="header-anchor" href="#_2-3-educational-link-object" aria-label="Permalink to &quot;2.3 Educational link object&quot;">​</a></h3><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">l</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Link label&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">u</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">t</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;intro&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p><code>t</code> (tier) must be one of:</p><ul><li><code>&quot;intro&quot;</code> — Wikipedia, NASA fact pages, agency overview pages</li><li><code>&quot;core&quot;</code> — MIT OCW, detailed technical pages, mission science overviews</li><li><code>&quot;deep&quot;</code> — Peer-reviewed papers, JPL technical reports, primary sources</li></ul><hr><h2 id="_3-data-quality-system" tabindex="-1">3. Data quality system <a class="header-anchor" href="#_3-data-quality-system" aria-label="Permalink to &quot;3. Data quality system&quot;">​</a></h2><p>Every mission carries a <code>data_quality</code> field that is displayed honestly in the UI.</p><table tabindex="0"><thead><tr><th>Value</th><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td><code>&quot;good&quot;</code></td><td><em>(none)</em></td><td>Primary sources available. Orbital elements from published data. Images from official agency archives</td></tr><tr><td><code>&quot;partial&quot;</code></td><td>⚠ PARTIAL DATA</td><td>Some data gaps. Orbital elements good; imagery sparse or selectively released. Must be explained in <code>data_note</code></td></tr><tr><td><code>&quot;reconstructed&quot;</code></td><td>◈ RECONSTRUCTED</td><td>Orbital elements computed from published launch parameters. No primary science data available. Surface imagery absent or unusable. Must be explained in <code>data_note</code></td></tr><tr><td><code>&quot;planned&quot;</code></td><td>◌ PLANNED</td><td>Mission not yet flown. Parameters from published mission design documents</td></tr></tbody></table><h3 id="known-reconstructed-missions" tabindex="-1">Known reconstructed missions <a class="header-anchor" href="#known-reconstructed-missions" aria-label="Permalink to &quot;Known reconstructed missions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mission</th><th>What is reconstructed</th><th>Source used</th></tr></thead><tbody><tr><td>Mars 3</td><td>Orbital elements computed from Proton-K launch date and published trajectory parameters</td><td>Siddiqi, <em>Beyond Earth</em> (NASA SP-4251, 2018)</td></tr><tr><td>Soviet Luna missions (pre-1970)</td><td>Partial orbital elements</td><td>Siddiqi, op. cit.</td></tr></tbody></table><h3 id="known-partial-data-missions" tabindex="-1">Known partial-data missions <a class="header-anchor" href="#known-partial-data-missions" aria-label="Permalink to &quot;Known partial-data missions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mission</th><th>What is partial</th><th>Note</th></tr></thead><tbody><tr><td>Mangalyaan</td><td>Imagery selectively released; telemetry reconstructed</td><td>Mission lost contact April 2022</td></tr><tr><td>Tianwen-1 / Zhurong</td><td>Selected data via CNSA official channels only</td><td>Zhurong status uncertain as of 2023</td></tr></tbody></table><hr><h2 id="_4-image-sources" tabindex="-1">4. Image sources <a class="header-anchor" href="#_4-image-sources" aria-label="Permalink to &quot;4. Image sources&quot;">​</a></h2><h3 id="_4-1-nasa-image-and-video-library" tabindex="-1">4.1 NASA Image and Video Library <a class="header-anchor" href="#_4-1-nasa-image-and-video-library" aria-label="Permalink to &quot;4.1 NASA Image and Video Library&quot;">​</a></h3><p><strong>API:</strong> <code>https://images-api.nasa.gov/search</code></p><p><strong>Parameters:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>q=[search query]</span></span>
<span class="line"><span>media_type=image</span></span>
<span class="line"><span>page_size=9</span></span></code></pre></div><p><strong>License:</strong> U.S. Government works — not subject to copyright in the United States. Free for educational use. Must credit NASA and the relevant centre (JPL, GSFC, JSC, etc.).</p><p><strong>Credit format:</strong> <code>© NASA/JPL-Caltech — U.S. Government work · Public domain</code></p><p><strong>Used for:</strong> All NASA mission gallery panels. Query strings are defined per mission in <code>gallery_query</code> field.</p><p><strong>Rate limiting:</strong> No authentication required for basic search. No formal rate limit documented; use conservatively.</p><h3 id="_4-2-esa-multimedia-archive" tabindex="-1">4.2 ESA Multimedia Archive <a class="header-anchor" href="#_4-2-esa-multimedia-archive" aria-label="Permalink to &quot;4.2 ESA Multimedia Archive&quot;">​</a></h3><p><strong>URL:</strong> <code>https://www.esa.int/ESA_Multimedia/</code></p><p><strong>License:</strong> CC BY-SA 3.0 IGO. May be used freely with attribution and share-alike. The IGO (Intergovernmental Organisation) variant is specifically designed for use by Wikipedia and similar projects.</p><p><strong>Credit format:</strong> <code>© ESA — CC BY-SA 3.0 IGO — esa.int</code></p><p><strong>Mars Express images:</strong> 1,430+ images available. HRSC stereo camera images released under CC BY-SA IGO.</p><p><strong>Used for:</strong> Mars Express gallery. ESA mission panels.</p><p><strong>Reference:</strong> <a href="https://www.esa.int/About_Us/Digital_Agenda/Open_Access_and_Creative_Commons" target="_blank" rel="noreferrer">https://www.esa.int/About_Us/Digital_Agenda/Open_Access_and_Creative_Commons</a></p><h3 id="_4-3-isro" tabindex="-1">4.3 ISRO <a class="header-anchor" href="#_4-3-isro" aria-label="Permalink to &quot;4.3 ISRO&quot;">​</a></h3><p><strong>URL:</strong> <code>https://www.isro.gov.in</code></p><p><strong>License:</strong> Available for educational and informational use. No explicit CC license. Do not use for commercial purposes.</p><p><strong>Credit format:</strong> <code>© ISRO — Educational use — isro.gov.in</code></p><p><strong>Mangalyaan (MOM) images:</strong> Mars Colour Camera (MCC) images released publicly. Mars Atlas (2015, 120 pages) available as PDF.</p><p><strong>Chandrayaan-3:</strong> Post-landing images released publicly.</p><p><strong>Used for:</strong> Mangalyaan and Chandrayaan gallery panels.</p><h3 id="_4-4-cnsa" tabindex="-1">4.4 CNSA <a class="header-anchor" href="#_4-4-cnsa" aria-label="Permalink to &quot;4.4 CNSA&quot;">​</a></h3><p><strong>URL:</strong> <code>https://www.cnsa.gov.cn</code></p><p><strong>License:</strong> Official releases. No explicit CC license. Use with attribution for educational context.</p><p><strong>Credit format:</strong> <code>© CNSA/CLEP — Official release — cnsa.gov.cn</code></p><p><strong>Tianwen-1 / Zhurong:</strong> Selected images released through CNSA and CLEP (China Lunar Exploration Program). Some available via Wikimedia Commons.</p><p><strong>Chang&#39;e missions:</strong> Official surface imagery released post-landing.</p><p><strong>Used for:</strong> CNSA mission gallery panels.</p><h3 id="_4-5-wikimedia-commons-—-curated-static-images" tabindex="-1">4.5 Wikimedia Commons — curated static images <a class="header-anchor" href="#_4-5-wikimedia-commons-—-curated-static-images" aria-label="Permalink to &quot;4.5 Wikimedia Commons — curated static images&quot;">​</a></h3><p>For missions where a live API fetch is not available, gallery images are served from Wikimedia Commons via direct URL. These are stable thumbnail URLs following the pattern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://upload.wikimedia.org/wikipedia/commons/thumb/[a]/[ab]/[filename]/[width]px-[filename]</span></span></code></pre></div><p>All Wikimedia Commons images carry their own license per file. Before adding an image, verify:</p><ol><li>The image page license tag (must be compatible with educational use)</li><li>The original source (prefer agency-released over third-party photographs)</li><li>The attribution requirements</li></ol><p><strong>Research task (03 phase):</strong> Curate and verify 3–5 Wikimedia Commons URLs per non-NASA mission for the gallery panels. Document source, license, and attribution per image.</p><h3 id="_4-6-soviet-russian-archive-—-special-case" tabindex="-1">4.6 Soviet/Russian archive — special case <a class="header-anchor" href="#_4-6-soviet-russian-archive-—-special-case" aria-label="Permalink to &quot;4.6 Soviet/Russian archive — special case&quot;">​</a></h3><p>Soviet-era imagery (Luna programme, Lunokhod) is patchy. Known accessible sources:</p><table tabindex="0"><thead><tr><th>Source</th><th>Content</th><th>Notes</th></tr></thead><tbody><tr><td>Roscosmos press archive</td><td>Modern releases only</td><td>Limited Soviet-era content</td></tr><tr><td>TASS photo archive</td><td>Historical mission team photos</td><td>May require licensing for some uses</td></tr><tr><td>Wikimedia Commons — Soviet space</td><td>Community-uploaded, varies by file</td><td>Check each image individually</td></tr><tr><td>Siddiqi, <em>Beyond Earth</em> (NASA SP-4251)</td><td>Comprehensive mission reference</td><td>Public domain NASA publication</td></tr></tbody></table><p><strong>Strategy for sparse missions:</strong> For missions where no usable imagery exists (e.g. Mars 3 surface transmission), the gallery panel shows an honest placeholder with a link to the best available secondary source, and the <code>data_quality</code> badge accurately reflects this.</p><hr><h2 id="_5-agency-logos" tabindex="-1">5. Agency logos <a class="header-anchor" href="#_5-agency-logos" aria-label="Permalink to &quot;5. Agency logos&quot;">​</a></h2><p>All agency logos are used under <strong>nominative use</strong> — for identification and attribution purposes only, in a non-commercial educational context. Orrery does not claim endorsement by any agency.</p><table tabindex="0"><thead><tr><th>Agency</th><th>Wikimedia Commons URL</th><th>Background colour</th><th>License status</th></tr></thead><tbody><tr><td>NASA</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/e/e5/NASA_logo.svg/200px-NASA_logo.svg.png</code></td><td>#0B3D91</td><td>Trademark — nominative use</td></tr><tr><td>ESA</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/7/76/ESA_logo_simple.svg/200px-ESA_logo_simple.svg.png</code></td><td>#1C3C8A</td><td>CC BY-SA 3.0 IGO</td></tr><tr><td>CNSA</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/CNSA_logo.svg/200px-CNSA_logo.svg.png</code></td><td>#DE2910</td><td>Trademark — nominative use</td></tr><tr><td>ISRO</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/b/b4/Indian_Space_Research_Organisation_Logo.svg/200px-Indian_Space_Research_Organisation_Logo.svg.png</code></td><td>#1a1a2e</td><td>Trademark — nominative use</td></tr><tr><td>Roscosmos</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/a/ac/Roscosmos_logo_en.svg/200px-Roscosmos_logo_en.svg.png</code></td><td>#0d0d1a</td><td>Trademark — nominative use</td></tr><tr><td>UAE/MBRSC</td><td><code>https://upload.wikimedia.org/wikipedia/en/thumb/e/e0/Mohammed_Bin_Rashid_Space_Centre_Logo.png/200px-Mohammed_Bin_Rashid_Space_Centre_Logo.png</code></td><td>#ffffff</td><td>Trademark — nominative use</td></tr><tr><td>JAXA</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/9/9f/JAXA_logo_2020.svg/200px-JAXA_logo_2020.svg.png</code></td><td>#0062AC</td><td>Trademark — nominative use</td></tr><tr><td>SpaceX</td><td><code>https://upload.wikimedia.org/wikipedia/commons/thumb/d/de/SpaceX-Logo.svg/200px-SpaceX-Logo.svg.png</code></td><td>#000000</td><td>Trademark — nominative use</td></tr></tbody></table><p><strong>Implementation:</strong> The <code>logoHTML()</code> function renders the real logo image on top of an always-visible text abbreviation fallback. If the image fails to load (offline use, URL change), the fallback renders correctly. In production, logos should be hosted locally from official media kits.</p><p><strong>Trademark notices:</strong> Every panel footer includes: <em>&quot;Logos are trademarks of their respective agencies · used for educational identification only.&quot;</em></p><hr><h2 id="_6-orbital-data-for-small-solar-system-bodies" tabindex="-1">6. Orbital data for small solar system bodies <a class="header-anchor" href="#_6-orbital-data-for-small-solar-system-bodies" aria-label="Permalink to &quot;6. Orbital data for small solar system bodies&quot;">​</a></h2><h3 id="_6-1-asteroid-belt-notable-objects" tabindex="-1">6.1 Asteroid belt notable objects <a class="header-anchor" href="#_6-1-asteroid-belt-notable-objects" aria-label="Permalink to &quot;6.1 Asteroid belt notable objects&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Body</th><th>Semi-major axis</th><th>Period</th><th>Inclination</th><th>Source</th></tr></thead><tbody><tr><td>Ceres</td><td>2.769 AU</td><td>4.61 yr</td><td>10.59°</td><td>JPL Small-Body Database</td></tr><tr><td>Vesta</td><td>2.361 AU</td><td>3.63 yr</td><td>7.14°</td><td>JPL Small-Body Database</td></tr></tbody></table><p><strong>JPL Small-Body Database:</strong> <code>https://ssd.jpl.nasa.gov/sbdb.cgi</code></p><h3 id="_6-2-kuiper-belt-objects" tabindex="-1">6.2 Kuiper Belt objects <a class="header-anchor" href="#_6-2-kuiper-belt-objects" aria-label="Permalink to &quot;6.2 Kuiper Belt objects&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Body</th><th>Semi-major axis</th><th>Period</th><th>Inclination</th><th>Note</th></tr></thead><tbody><tr><td>Pluto</td><td>39.48 AU</td><td>248.0 yr</td><td>17.14°</td><td>IAU dwarf planet</td></tr><tr><td>Eris</td><td>67.86 AU (mean)</td><td>559 yr</td><td>44.04°</td><td>Scattered disc object</td></tr><tr><td>Makemake</td><td>45.79 AU</td><td>309.9 yr</td><td>28.96°</td><td>Classical KBO</td></tr><tr><td>Haumea</td><td>43.13 AU</td><td>284.1 yr</td><td>28.19°</td><td>Classical KBO</td></tr></tbody></table><h3 id="_6-3-notable-comets" tabindex="-1">6.3 Notable comets <a class="header-anchor" href="#_6-3-notable-comets" aria-label="Permalink to &quot;6.3 Notable comets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Body</th><th>Perihelion q</th><th>Aphelion Q</th><th>Period</th><th>Inclination</th><th>Note</th></tr></thead><tbody><tr><td>Halley&#39;s Comet</td><td>0.586 AU</td><td>35.1 AU</td><td>75.3 yr</td><td>162.3°</td><td>Retrograde orbit</td></tr><tr><td>67P/C-G</td><td>1.21 AU</td><td>5.68 AU</td><td>6.44 yr</td><td>7.04°</td><td>Rosetta mission target</td></tr><tr><td>ʻOumuamua</td><td>0.255 AU</td><td>—</td><td>—</td><td>122.7°</td><td>Hyperbolic — interstellar</td></tr></tbody></table><p><strong>Source:</strong> JPL Horizons — <code>https://ssd.jpl.nasa.gov/horizons/</code></p><hr><h2 id="_7-earth-orbit-data" tabindex="-1">7. Earth orbit data <a class="header-anchor" href="#_7-earth-orbit-data" aria-label="Permalink to &quot;7. Earth orbit data&quot;">​</a></h2><h3 id="_7-1-orbital-objects-in-p05" tabindex="-1">7.1 Orbital objects in P05 <a class="header-anchor" href="#_7-1-orbital-objects-in-p05" aria-label="Permalink to &quot;7.1 Orbital objects in P05&quot;">​</a></h3><p>All data from publicly available sources. Altitudes are mean values; actual orbits vary.</p><table tabindex="0"><thead><tr><th>Object</th><th>Regime</th><th>Altitude</th><th>Period</th><th>Inclination</th><th>Agency</th><th>Source</th></tr></thead><tbody><tr><td>ISS</td><td>LEO</td><td>408 km</td><td>92.9 min</td><td>51.6°</td><td>Multi-agency</td><td>NASA</td></tr><tr><td>Tiangong</td><td>LEO</td><td>389 km</td><td>91.5 min</td><td>41.5°</td><td>CNSA</td><td>CNSA</td></tr><tr><td>Hubble</td><td>LEO</td><td>547 km</td><td>95.4 min</td><td>28.5°</td><td>NASA/ESA</td><td>NASA</td></tr><tr><td>GPS constellation</td><td>MEO</td><td>20,200 km</td><td>717.9 min</td><td>55.0°</td><td>USAF</td><td>GPS.gov</td></tr><tr><td>Galileo constellation</td><td>MEO</td><td>23,222 km</td><td>844.8 min</td><td>56.0°</td><td>EU/ESA</td><td>ESA</td></tr><tr><td>GLONASS</td><td>MEO</td><td>19,100 km</td><td>675.7 min</td><td>64.8°</td><td>Roscosmos</td><td>Roscosmos</td></tr><tr><td>BeiDou (MEO)</td><td>MEO</td><td>21,528 km</td><td>760 min</td><td>55.0°</td><td>CNSA</td><td>CNSA</td></tr><tr><td>GOES (GEO)</td><td>GEO</td><td>35,786 km</td><td>1436 min</td><td>0.0°</td><td>NOAA/NASA</td><td>NOAA</td></tr><tr><td>Chandra</td><td>HEO</td><td>9,942–133,000 km</td><td>3808 min</td><td>76.7°</td><td>NASA</td><td>CXC</td></tr><tr><td>XMM-Newton</td><td>HEO</td><td>7,365–113,946 km</td><td>3168 min</td><td>40.0°</td><td>ESA</td><td>ESA</td></tr><tr><td>LRO</td><td>Lunar orbit</td><td>50 km (Moon)</td><td>118 min</td><td>90.0°</td><td>NASA</td><td>NASA</td></tr><tr><td>JWST</td><td>L2</td><td>1,500,000 km</td><td>—</td><td>—</td><td>NASA/ESA/CSA</td><td>NASA</td></tr><tr><td>Gaia</td><td>L2</td><td>1,500,000 km</td><td>—</td><td>—</td><td>ESA</td><td>ESA</td></tr></tbody></table><hr><h2 id="_8-mission-trajectory-data-for-the-library-panel" tabindex="-1">8. Mission trajectory data for the library panel <a class="header-anchor" href="#_8-mission-trajectory-data-for-the-library-panel" aria-label="Permalink to &quot;8. Mission trajectory data for the library panel&quot;">​</a></h2><p>For the 2D trajectory preview in the mission library, trajectories are drawn using each mission&#39;s J2000 departure day and transit time. Planetary positions are computed at departure and arrival using the formulas in section 1.4.</p><p>Moon missions use a separate Earth-Moon diagram (not solar-system scale). The <code>dest</code> field controls which renderer is used.</p><h3 id="_8-1-mars-mission-j2000-day-offsets" tabindex="-1">8.1 Mars mission J2000 day offsets <a class="header-anchor" href="#_8-1-mars-mission-j2000-day-offsets" aria-label="Permalink to &quot;8.1 Mars mission J2000 day offsets&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mission</th><th>J2000 departure</th><th>Computed from</th></tr></thead><tbody><tr><td>Mariner 4</td><td>−12,820</td><td>Nov 28, 1964</td></tr><tr><td>Mars 3</td><td>−10,445</td><td>May 28, 1971</td></tr><tr><td>Viking 1</td><td>−8,899</td><td>Aug 20, 1975</td></tr><tr><td>Mars Pathfinder</td><td>−1,123</td><td>Dec 4, 1996</td></tr><tr><td>Mars Express</td><td>1,248</td><td>Jun 2, 2003</td></tr><tr><td>Curiosity</td><td>4,347</td><td>Nov 26, 2011</td></tr><tr><td>MAVEN</td><td>4,969</td><td>Nov 18, 2013</td></tr><tr><td>Mangalyaan</td><td>4,962</td><td>Nov 5, 2013</td></tr><tr><td>InSight</td><td>6,699</td><td>May 5, 2018</td></tr><tr><td>Hope Probe</td><td>7,500</td><td>Jul 19, 2020</td></tr><tr><td>Tianwen-1</td><td>7,508</td><td>Jul 23, 2020</td></tr><tr><td>Perseverance</td><td>7,511</td><td>Jul 30, 2020</td></tr></tbody></table><hr><h2 id="_9-educational-link-system" tabindex="-1">9. Educational link system <a class="header-anchor" href="#_9-educational-link-system" aria-label="Permalink to &quot;9. Educational link system&quot;">​</a></h2><p>Orrery uses a three-tier educational link system, colour-coded consistently across all screens:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Colour</th><th>Purpose</th><th>Examples</th></tr></thead><tbody><tr><td><strong>INTRO</strong></td><td>Teal <code>#4ecdc4</code></td><td>Wikipedia, NASA fact pages, agency mission pages</td><td>Wikipedia articles, nasa.gov/mission/</td></tr><tr><td><strong>CORE</strong></td><td>Blue <code>#7b9cff</code></td><td>Technical explainers, MIT OCW, deeper mission science</td><td>MIT OpenCourseWare, JPL education pages</td></tr><tr><td><strong>DEEP</strong></td><td>Red <code>#ff9090</code></td><td>Peer-reviewed papers, JPL technical reports, primary sources</td><td>Science, Nature, AJ, NTRS</td></tr></tbody></table><h3 id="key-curated-links-reused-across-screens" tabindex="-1">Key curated links (reused across screens) <a class="header-anchor" href="#key-curated-links-reused-across-screens" aria-label="Permalink to &quot;Key curated links (reused across screens)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Link</th><th>Tier</th><th>URL</th></tr></thead><tbody><tr><td>Hohmann transfer orbit</td><td>INTRO</td><td><a href="https://en.wikipedia.org/wiki/Hohmann_transfer_orbit" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Hohmann_transfer_orbit</a></td></tr><tr><td>Tsiolkovsky rocket equation</td><td>INTRO</td><td><a href="https://en.wikipedia.org/wiki/Tsiolkovsky_rocket_equation" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Tsiolkovsky_rocket_equation</a></td></tr><tr><td>Porkchop plot</td><td>CORE</td><td><a href="https://en.wikipedia.org/wiki/Porkchop_plot" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Porkchop_plot</a></td></tr><tr><td>JPL launch windows lesson</td><td>CORE</td><td><a href="https://www.jpl.nasa.gov/edu/resources/lesson-plan/lets-go-to-mars-calculating-launch-windows/" target="_blank" rel="noreferrer">https://www.jpl.nasa.gov/edu/resources/lesson-plan/lets-go-to-mars-calculating-launch-windows/</a></td></tr><tr><td>NASA Glenn rocket equation</td><td>CORE</td><td><a href="https://www1.grc.nasa.gov/beginners-guide-to-aeronautics/ideal-rocket-equation/" target="_blank" rel="noreferrer">https://www1.grc.nasa.gov/beginners-guide-to-aeronautics/ideal-rocket-equation/</a></td></tr><tr><td>Lagrange point</td><td>CORE</td><td><a href="https://en.wikipedia.org/wiki/Lagrange_point" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Lagrange_point</a></td></tr><tr><td>Lunar water ice (Science 2018)</td><td>DEEP</td><td><a href="https://www.science.org/doi/10.1126/science.aap8637" target="_blank" rel="noreferrer">https://www.science.org/doi/10.1126/science.aap8637</a></td></tr><tr><td>Batygin &amp; Brown — Planet Nine (AJ 2016)</td><td>DEEP</td><td><a href="https://iopscience.iop.org/article/10.3847/0004-6256/151/2/22" target="_blank" rel="noreferrer">https://iopscience.iop.org/article/10.3847/0004-6256/151/2/22</a></td></tr></tbody></table><hr><h2 id="_10-one-off-research-plan-for-sparse-missions" tabindex="-1">10. One-off research plan for sparse missions <a class="header-anchor" href="#_10-one-off-research-plan-for-sparse-missions" aria-label="Permalink to &quot;10. One-off research plan for sparse missions&quot;">​</a></h2><p>The following missions require dedicated research sessions to fill gaps before 02 (formal project concept) is finalised. Each session produces: curated image URLs, verified orbital data, and updated <code>data_note</code> text.</p><table tabindex="0"><thead><tr><th>Mission</th><th>Gap</th><th>Research approach</th><th>Priority</th></tr></thead><tbody><tr><td>Mars 3</td><td>No usable surface imagery; team photos only</td><td>Wikimedia Commons excavation; TASS historical archive; Siddiqi NASA SP-4251</td><td>HIGH</td></tr><tr><td>Luna programme (1966–1976)</td><td>Variable data quality across 24 missions</td><td>Siddiqi; Soviet Space Encyclopaedia; Wikimedia Commons</td><td>MEDIUM</td></tr><tr><td>Mangalyaan</td><td>Full imagery catalogue not publicly indexed</td><td>ISRO image gallery manual curation; Indian news archives</td><td>MEDIUM</td></tr><tr><td>Chang&#39;e 4 / Zhurong</td><td>Current status uncertain 2023+</td><td>CNSA official announcements; CLEP press releases</td><td>MEDIUM</td></tr><tr><td>Soviet Lunokhod missions</td><td>Routes and images partially documented</td><td>LROC spotting images (NASA); Wikimedia Commons</td><td>LOW</td></tr><tr><td>Beresheet (Israel, 2019)</td><td>Crashed — limited official imagery</td><td>SpaceIL press archive; Wikimedia Commons</td><td>LOW</td></tr></tbody></table><hr><h2 id="_11-credit-format-reference" tabindex="-1">11. Credit format reference <a class="header-anchor" href="#_11-credit-format-reference" aria-label="Permalink to &quot;11. Credit format reference&quot;">​</a></h2><p>Every image, logo, and data source in Orrery uses one of the following credit formats:</p><p><strong>NASA imagery:</strong><code>© NASA/[Centre] — U.S. Government work · Public domain</code></p><p><strong>ESA imagery:</strong><code>© ESA — CC BY-SA 3.0 IGO — esa.int</code></p><p><strong>ISRO imagery:</strong><code>© ISRO — Educational use — isro.gov.in</code></p><p><strong>CNSA imagery:</strong><code>© CNSA/CLEP — Official release — cnsa.gov.cn</code></p><p><strong>Roscosmos / Soviet:</strong><code>© Roscosmos / Soviet Space Program — Historical archive</code></p><p><strong>JAXA imagery:</strong><code>© JAXA — jaxa.jp</code></p><p><strong>Wikimedia Commons image:</strong><code>[Author], [License], via Wikimedia Commons</code></p><p><strong>Agency logos (all):</strong><code>[Agency] logo is a trademark of [Agency] · Used for educational identification only</code></p><hr><p><em>Orrery · 03 Data Catalog · April 2026 · Living document</em><em>Next: 04 Technical Architecture →</em></p>`,145)])])}const m=e(o,[["render",i]]);export{u as __pageData,m as default};
